#!/usr/bin/env python3
"""Corpus prompt builder for TwoTower-Sovereign P2-XL.

Assembles a LARGE, diverse set of (prompt, real-continuation) token pairs from the
repo's own prose (markdown docs + READMEs). For each prose window:
    prompt  = first  PROMPT_LEN tokens   (what the frozen SSM ingests)
    target  = next   K          tokens   (the REAL corpus continuation)
Tokenized with the SAME gpt-neox/pythia BPE the mamba-2.8b canary uses (vocab 50280).

This replaces the greedy-generated targets of train_p2_scaled with HONEST real-text
targets: it tests whether the frozen pure-SSM context predicts *real* continuations,
and it makes extraction ~1 canary call per prompt (no K-step greedy loop).
"""
import hashlib
import os
import re
import sys

_HERE = os.path.dirname(os.path.abspath(__file__))
_ROOT = os.path.abspath(os.path.join(_HERE, "..", "..", ".."))

# Prose sources: markdown docs + open-source READMEs/docs. Skip code-heavy trees.
CORPUS_DIRS = [
    os.path.join(_ROOT, "docs"),
    os.path.join(_ROOT, "open-source", "gnosis", "docs"),
    os.path.join(_ROOT, "open-source", "aeon", "docs"),
    os.path.join(_ROOT, "open-source", "buleyean-rl"),
]

_FENCE = re.compile(r"```.*?```", re.DOTALL)
_INLINE_CODE = re.compile(r"`[^`]*`")
_LINK = re.compile(r"\[([^\]]*)\]\([^)]*\)")
_IMG = re.compile(r"!\[[^\]]*\]\([^)]*\)")
_HTML = re.compile(r"<[^>]+>")
_HDR = re.compile(r"^\s{0,3}#{1,6}\s+")
_MDNOISE = re.compile(r"[*_#>`|]")
_WORD = re.compile(r"[A-Za-z]{2,}")
_WS = re.compile(r"\s+")


def clean_markdown(text: str) -> str:
    text = _FENCE.sub(" ", text)
    text = _IMG.sub(" ", text)
    text = _LINK.sub(r"\1", text)
    text = _HTML.sub(" ", text)
    return text


def iter_prose_paragraphs(text: str):
    """Yield natural-prose paragraphs (>= 8 alphabetic words, not tables/headings/code)."""
    text = clean_markdown(text)
    for para in re.split(r"\n\s*\n", text):
        lines = []
        for ln in para.splitlines():
            s = ln.strip()
            if not s or s.startswith("|") or s.startswith("- ") or s.startswith("* ") \
               or s.startswith("+ ") or re.match(r"^\d+\.\s", s) or _HDR.match(s) \
               or s.startswith("http") or s.count("|") >= 2:
                continue
            lines.append(s)
        joined = " ".join(lines)
        joined = _INLINE_CODE.sub(" ", joined)
        joined = _MDNOISE.sub(" ", joined)
        joined = _WS.sub(" ", joined).strip()
        if len(_WORD.findall(joined)) >= 10 and joined:
            yield joined


def build_corpus_prompts(tok, target_n=3600, prompt_len=6, k=8, stride=24, seed=0):
    """Return list of dicts {prompt, prompt_ids, target_ids} — deduped, diverse."""
    need = prompt_len + k
    files = []
    for d in CORPUS_DIRS:
        for root, _dirs, names in os.walk(d):
            if "/node_modules/" in root or "/.git/" in root:
                continue
            for nm in names:
                if nm.endswith(".md"):
                    files.append(os.path.join(root, nm))
    files.sort()
    # Deterministic shuffle for diversity across the tree.
    import random
    random.Random(seed).shuffle(files)

    seen = set()
    out = []
    for fp in files:
        if len(out) >= target_n:
            break
        try:
            with open(fp, encoding="utf-8", errors="ignore") as f:
                raw = f.read()
        except Exception:  # noqa: BLE001
            continue
        for para in iter_prose_paragraphs(raw):
            if len(out) >= target_n:
                break
            ids = tok.encode(para)
            if len(ids) < need:
                continue
            # Strided windows within the paragraph (opening + later sentences).
            for start in range(0, len(ids) - need + 1, stride):
                if len(out) >= target_n:
                    break
                p_ids = ids[start:start + prompt_len]
                t_ids = ids[start + prompt_len:start + prompt_len + k]
                key = hashlib.md5(bytes(str(p_ids), "utf8")).hexdigest()[:16]
                if key in seen:
                    continue
                # Skip windows that are mostly whitespace/degenerate tokens.
                ptxt = tok.decode(p_ids)
                if len(ptxt.strip()) < 4:
                    continue
                seen.add(key)
                out.append({
                    "key": key,
                    "prompt": ptxt,
                    "prompt_ids": list(p_ids),
                    "target_ids": list(t_ids),
                    "target_text": tok.decode(t_ids),
                })
    return out


if __name__ == "__main__":
    from transformers import AutoTokenizer
    tok = AutoTokenizer.from_pretrained("EleutherAI/gpt-neox-20b")
    n = int(sys.argv[1]) if len(sys.argv) > 1 else 3600
    prompts = build_corpus_prompts(tok, target_n=n)
    print(f"built {len(prompts)} prompts")
    import numpy as np
    all_t = [t for p in prompts for t in p["target_ids"]]
    print(f"distinct target tokens: {len(set(all_t))}  (V if compacted)")
    print(f"distinct prompts: {len(set(p['key'] for p in prompts))}")
    for p in prompts[:8]:
        print(f"  {p['prompt']!r:50s} -> {p['target_text']!r}")
